package cmd

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"os"
	"os/signal"
	"path/filepath"
	"syscall"
	"time"

	"github.com/CosmoLabs-org/cosmo-smoke/internal/reporter"
	"github.com/CosmoLabs-org/cosmo-smoke/internal/runner"
	"github.com/CosmoLabs-org/cosmo-smoke/internal/schema"
	"github.com/spf13/cobra"
)

var serveCmd = &cobra.Command{
	Use:   "serve",
	Short: "Start HTTP health endpoint for container probes",
	Long:  "Expose a /healthz endpoint that runs smoke tests on each request",
	RunE:  runServe,
}

var (
	servePort       string
	servePath       string
	serveConfigFile string
)

func init() {
	rootCmd.AddCommand(serveCmd)
	serveCmd.Flags().StringVarP(&servePort, "port", "p", "8080", "Port to listen on")
	serveCmd.Flags().StringVar(&servePath, "path", "/healthz", "Health endpoint path")
	serveCmd.Flags().StringVarP(&serveConfigFile, "file", "f", ".smoke.yaml", "Config file path")
}

// noopReporter satisfies reporter.Reporter without emitting any output.
type noopReporter struct{}

func newNoopReporter() *noopReporter { return &noopReporter{} }

func (n *noopReporter) PrereqStart(_ string)                              {}
func (n *noopReporter) PrereqResult(_ reporter.PrereqResultData)          {}
func (n *noopReporter) TestStart(_ string)                                {}
func (n *noopReporter) TestResult(_ reporter.TestResultData)              {}
func (n *noopReporter) Summary(_ reporter.SuiteResultData)                {}

// healthResponse is the JSON body returned by the health endpoint.
type healthResponse struct {
	Status     string      `json:"status"`
	Tests      testCounts  `json:"tests"`
	DurationMs int64       `json:"duration_ms"`
}

type testCounts struct {
	Total  int `json:"total"`
	Passed int `json:"passed"`
	Failed int `json:"failed"`
}

// buildHandler returns an http.HandlerFunc that runs smoke tests on every
// request and responds with the appropriate status and JSON body.
func buildHandler(configFile string) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()

		cfg, err := schema.Load(configFile)
		if err != nil {
			writeHealthError(w, http.StatusInternalServerError, fmt.Sprintf("load config: %v", err))
			return
		}
		if err := schema.Validate(cfg); err != nil {
			writeHealthError(w, http.StatusInternalServerError, fmt.Sprintf("invalid config: %v", err))
			return
		}

		configDir := filepath.Dir(configFile)
		if !filepath.IsAbs(configDir) {
			cwd, _ := os.Getwd()
			configDir = filepath.Join(cwd, configDir)
		}

		noop := newNoopReporter()
		rn := &runner.Runner{
			Config:    cfg,
			Reporter:  noop,
			ConfigDir: configDir,
		}

		result, err := rn.Run(runner.RunOptions{})
		elapsed := time.Since(start)
		if err != nil {
			writeHealthError(w, http.StatusInternalServerError, fmt.Sprintf("run: %v", err))
			return
		}

		status := "healthy"
		httpStatus := http.StatusOK
		if result.Failed > 0 {
			status = "unhealthy"
			httpStatus = http.StatusServiceUnavailable
		}

		resp := healthResponse{
			Status: status,
			Tests: testCounts{
				Total:  result.Total,
				Passed: result.Passed,
				Failed: result.Failed,
			},
			DurationMs: elapsed.Milliseconds(),
		}

		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(httpStatus)
		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")
		enc.Encode(resp) //nolint:errcheck
	}
}

func writeHealthError(w http.ResponseWriter, code int, msg string) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(code)
	json.NewEncoder(w).Encode(map[string]string{"error": msg}) //nolint:errcheck
}

func runServe(cmd *cobra.Command, args []string) error {
	addr := ":" + servePort

	mux := http.NewServeMux()
	mux.HandleFunc(servePath, buildHandler(serveConfigFile))

	srv := &http.Server{
		Addr:    addr,
		Handler: mux,
	}

	// Graceful shutdown on SIGINT/SIGTERM.
	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		<-quit
		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
		defer cancel()
		srv.Shutdown(ctx) //nolint:errcheck
	}()

	fmt.Fprintf(os.Stderr, "smoke serve listening on %s%s\n", addr, servePath)
	if err := srv.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		return err
	}
	return nil
}

package cmd

import (
	"fmt"
	"os"

	"github.com/CosmoLabs-org/cosmo-smoke/internal/migrate/goss"
	"github.com/CosmoLabs-org/cosmo-smoke/internal/schema"
	"github.com/spf13/cobra"
)

var (
	migrateOutput    string
	migrateOverwrite bool
	migrateStrict    bool
	migrateStats     bool
	migrateDistro    string
)

var migrateCmd = &cobra.Command{
	Use:   "migrate",
	Short: "Migrate from other test frameworks",
	Long:  "Migrate configuration files from other test frameworks to cosmo-smoke format.",
}

var gossCmd = &cobra.Command{
	Use:   "goss <input.yaml>",
	Short: "Migrate a Goss YAML file to .smoke.yaml",
	Long: `Migrate a Goss YAML configuration to cosmo-smoke format.

Supports all Goss resource types. Core keys (process, port, command, file,
http, package, service) are mapped to native cosmo-smoke assertions. Other
keys are mapped via command fallback with TODO comments for attributes that
lack native support.

Examples:
  smoke migrate goss goss.yaml
  smoke migrate goss goss.yaml -o .smoke.yaml
  smoke migrate goss goss.yaml --strict --stats
  smoke migrate goss goss.yaml --distro rpm -o smoke.yaml`,
	Args: cobra.ExactArgs(1),
	RunE: runMigrateGoss,
}

func init() {
	gossCmd.Flags().StringVarP(&migrateOutput, "output", "o", "", "Output .smoke.yaml path (default: stdout)")
	gossCmd.Flags().BoolVar(&migrateOverwrite, "overwrite", false, "Overwrite output file if it exists")
	gossCmd.Flags().BoolVar(&migrateStrict, "strict", false, "Fail on any unmappable assertion")
	gossCmd.Flags().BoolVar(&migrateStats, "stats", false, "Print mapping stats to stderr")
	gossCmd.Flags().StringVar(&migrateDistro, "distro", "deb", "Linux distro for package commands: deb|rpm|apk")

	migrateCmd.AddCommand(gossCmd)
	rootCmd.AddCommand(migrateCmd)
}

func runMigrateGoss(cmd *cobra.Command, args []string) error {
	inputPath := args[0]

	// Validate distro flag
	switch migrateDistro {
	case "deb", "rpm", "apk":
		// valid
	default:
		return fmt.Errorf("unsupported distro %q: must be deb, rpm, or apk", migrateDistro)
	}

	// Read input
	data, err := os.ReadFile(inputPath)
	if err != nil {
		return fmt.Errorf("reading %s: %w", inputPath, err)
	}

	// Parse Goss YAML
	gf, err := goss.Parse(data)
	if err != nil {
		return fmt.Errorf("parsing goss file: %w", err)
	}

	// Translate to cosmo-smoke tests
	tests, warnings := goss.Translate(gf, goss.TranslateOptions{
		Distro: migrateDistro,
	})

	// Strict mode: fail if any warnings
	if migrateStrict && len(warnings) > 0 {
		fmt.Fprintf(os.Stderr, "Strict mode: %d unmappable assertions found\n", len(warnings))
		for _, w := range warnings {
			fmt.Fprintf(os.Stderr, "  [%s] %s: %s\n", w.GossKey, w.Resource, w.Message)
		}
		os.Exit(1)
	}

	// Emit output
	output, err := goss.Emit(tests, warnings, goss.EmitMeta{
		Source: inputPath,
	})
	if err != nil {
		return fmt.Errorf("generating output: %w", err)
	}

	// Validate emitted YAML parses back
	if _, err := schema.Parse([]byte(output)); err != nil {
		return fmt.Errorf("generated output is not valid .smoke.yaml: %w", err)
	}

	// Print stats if requested
	if migrateStats {
		fmt.Fprintln(os.Stderr, goss.EmitStats(warnings))
	}

	// Write output
	if migrateOutput != "" {
		if _, err := os.Stat(migrateOutput); err == nil && !migrateOverwrite {
			return fmt.Errorf("output file %s already exists (use --overwrite)", migrateOutput)
		}
		if err := os.WriteFile(migrateOutput, []byte(output), 0644); err != nil {
			return fmt.Errorf("writing output: %w", err)
		}
		fmt.Fprintf(os.Stderr, "Wrote %s\n", migrateOutput)
	} else {
		fmt.Print(output)
	}

	return nil
}

