			t.Errorf("expected application/json content-type, got %s", ct)
		}

		resp := map[string]any{
			"data": map[string]any{
				"__schema": map[string]any{
					"types": []map[string]any{
						{"name": "Query"},
						{"name": "Mutation"},
						{"name": "User"},
					},
				},
			},
		}
		json.NewEncoder(w).Encode(resp)
	}))
	defer server.Close()

	check := &schema.GraphQLCheck{URL: server.URL}
	results := CheckGraphQL(check)

	if len(results) == 0 {
